const ADMIN_HTML_B64 = "";
const ADMIN_HTML = (function() {
  const bin = atob(ADMIN_HTML_B64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return new TextDecoder().decode(bytes);
})();

const CORS_HEADERS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, DELETE, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-API-Key',
};

function json(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json', ...CORS_HEADERS },
  });
}

function generateKey() {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  let key = 'tts_';
  for (let i = 0; i < 32; i++) {
    key += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return key;
}

// Extract API key from request
function getApiKey(request) {
  const auth = request.headers.get('Authorization');
  if (auth && auth.startsWith('Bearer ')) return auth.slice(7);
  return request.headers.get('X-API-Key');
}

// Check if request is from admin
function isAdmin(request, env) {
  const token = getApiKey(request);
  return token === env.ADMIN_TOKEN;
}

// Rate limit check (simple: count requests in last minute)
async function checkRateLimit(db, apiKey, limit) {
  const oneMinAgo = new Date(Date.now() - 60000).toISOString();
  const result = await db.prepare(
    'SELECT COUNT(*) as cnt FROM usage_logs WHERE api_key = ? AND created_at > ?'
  ).bind(apiKey, oneMinAgo).first();
  return (result?.cnt || 0) < limit;
}

// Log usage
async function logUsage(db, apiKey, endpoint, textLength, responseTimeMs, status) {
  await db.prepare(
    'INSERT INTO usage_logs (api_key, endpoint, text_length, response_time_ms, status) VALUES (?, ?, ?, ?, ?)'
  ).bind(apiKey, endpoint, textLength, responseTimeMs, status).run();

  await db.prepare(
    'UPDATE api_keys SET usage_count = usage_count + 1, last_used = datetime("now") WHERE key = ?'
  ).bind(apiKey).run();
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;

    // CORS preflight
    if (request.method === 'OPTIONS') {
      return new Response(null, { headers: CORS_HEADERS });
    }

    // === Public endpoints (no auth) ===
    if (path === '/health' && request.method === 'GET') {
      // Proxy health to origin
      try {
        const origin = await fetch(`${env.ORIGIN_URL}/health`);
        const data = await origin.json();
        return json({ ...data, gateway: 'ok' });
      } catch (e) {
        return json({ gateway: 'ok', origin: 'unreachable' });
      }
    }

    if (path === '/voices' && request.method === 'GET') {
      const origin = await fetch(`${env.ORIGIN_URL}/voices`);
      const data = await origin.json();
      return json(data);
    }

    // === Admin panel (no auth - login is in-page) ===
    if (path === '/admin/' || path === '/admin/index.html') {
      return new Response(ADMIN_HTML, {
        headers: { 'Content-Type': 'text/html; charset=utf-8', ...CORS_HEADERS },
      });
    }

    // === Admin API endpoints ===
    if (path.startsWith('/admin/')) {
      if (!isAdmin(request, env)) {
        return json({ error: 'Unauthorized' }, 401);
      }
      return handleAdmin(request, env, path);
    }

    // === Protected endpoints (require API key) ===
    if (path === '/tts' && request.method === 'POST') {
      return handleTTS(request, env);
    }

    // Proxy key management (admin only via API key)
    if (path.startsWith('/proxy/')) {
      if (!isAdmin(request, env)) {
        return json({ error: 'Unauthorized' }, 401);
      }
      const origin = await fetch(`${env.ORIGIN_URL}${path}`, {
        method: request.method,
        headers: request.headers,
        body: request.method === 'POST' ? await request.text() : undefined,
      });
      return new Response(origin.body, { status: origin.status, headers: { ...CORS_HEADERS } });
    }

    // Serve admin panel
    if (path === '/' || path === '/admin') {
      return Response.redirect(url.origin + '/admin/', 301);
    }

    return json({ error: 'Not found' }, 404);
  }
};

// Pricing: 1 VND per character
const COST_PER_CHAR = 1;

// Handle TTS requests with auth
async function handleTTS(request, env) {
  const apiKey = getApiKey(request);
  if (!apiKey) {
    return json({ error: 'API key required. Use header: Authorization: Bearer <key>' }, 401);
  }

  // Validate key
  const keyRow = await env.DB.prepare(
    'SELECT * FROM api_keys WHERE key = ? AND active = 1'
  ).bind(apiKey).first();

  if (!keyRow) {
    return json({ error: 'Invalid or inactive API key' }, 403);
  }

  // Check expiry
  if (keyRow.expires_at && new Date(keyRow.expires_at) < new Date()) {
    return json({ error: 'API key expired' }, 403);
  }

  // Rate limit
  const allowed = await checkRateLimit(env.DB, apiKey, keyRow.rate_limit);
  if (!allowed) {
    return json({ error: `Rate limit exceeded (${keyRow.rate_limit} req/min)` }, 429);
  }

  // Parse body
  const t0 = Date.now();
  let body;
  try {
    body = await request.json();
  } catch {
    return json({ error: 'Invalid JSON' }, 400);
  }

  const textLen = body.text?.length || 0;
  const voiceId = body.voice_id || 'NOpBlnGInO9m6vDvFkFC';
  const textPreview = (body.text || '').slice(0, 80);
  const clientIp = request.headers.get('cf-connecting-ip') || request.headers.get('x-forwarded-for') || 'unknown';
  const cost = textLen * COST_PER_CHAR;

  // Check balance
  if (keyRow.balance < cost) {
    return json({
      error: 'Insufficient balance',
      balance: keyRow.balance,
      cost: cost,
      need: cost - keyRow.balance,
    }, 402);
  }

  // Proxy to origin
  try {
    const origin = await fetch(`${env.ORIGIN_URL}/tts`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });

    const responseTime = Date.now() - t0;

    if (origin.status === 200) {
      // Deduct balance
      await env.DB.prepare(
        'UPDATE api_keys SET balance = balance - ?, total_spent = total_spent + ?, usage_count = usage_count + 1, last_used = datetime("now") WHERE key = ?'
      ).bind(cost, cost, apiKey).run();

      // Log usage with details
      await env.DB.prepare(
        'INSERT INTO usage_logs (api_key, endpoint, text_length, response_time_ms, status, cost, chars, voice_id, text_preview, ip, key_name) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'
      ).bind(apiKey, '/tts', textLen, responseTime, 200, cost, textLen, voiceId, textPreview, clientIp, keyRow.name).run();

      // Log transaction
      await env.DB.prepare(
        'INSERT INTO transactions (api_key, amount, type, note) VALUES (?, ?, ?, ?)'
      ).bind(apiKey, -cost, 'usage', `TTS ${textLen} chars`).run();

      return new Response(origin.body, {
        status: 200,
        headers: {
          'Content-Type': 'audio/mpeg',
          'Content-Disposition': 'attachment; filename=tts.mp3',
          'X-Response-Time': `${responseTime}ms`,
          'X-Cost': `${cost}`,
          'X-Balance': `${keyRow.balance - cost}`,
          ...CORS_HEADERS,
        },
      });
    } else {
      // Don't charge on failure
      const err = await origin.text();
      await env.DB.prepare(
        'INSERT INTO usage_logs (api_key, endpoint, text_length, response_time_ms, status, cost, chars, voice_id, text_preview, ip, key_name, error_msg) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'
      ).bind(apiKey, '/tts', textLen, responseTime, origin.status, 0, textLen, voiceId, textPreview, clientIp, keyRow.name, err.slice(0, 200)).run();

      return json({ error: err }, origin.status);
    }
  } catch (e) {
    const responseTime = Date.now() - t0;
    await env.DB.prepare(
      'INSERT INTO usage_logs (api_key, endpoint, text_length, response_time_ms, status, cost, chars, voice_id, text_preview, ip, key_name, error_msg) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)'
    ).bind(apiKey, '/tts', textLen, responseTime, 500, 0, textLen, voiceId, textPreview, clientIp, keyRow.name, e.message.slice(0, 200)).run();
    return json({ error: 'Origin server error: ' + e.message }, 500);
  }
}

// Admin API handlers
async function handleAdmin(request, env, path) {
  const method = request.method;

  // GET /admin/keys — list all keys
  if (path === '/admin/keys' && method === 'GET') {
    const { results } = await env.DB.prepare(
      'SELECT id, key, name, email, created_at, active, usage_count, last_used, rate_limit, expires_at, balance, total_spent FROM api_keys ORDER BY created_at DESC'
    ).all();
    return json({ keys: results });
  }

  // POST /admin/keys — create new key
  if (path === '/admin/keys' && method === 'POST') {
    const body = await request.json();
    const key = generateKey();
    const name = body.name || 'Unnamed';
    const email = body.email || null;
    const rateLimit = body.rate_limit || 10;
    const expiresAt = body.expires_at || null;
    const balance = body.balance || 0;

    await env.DB.prepare(
      'INSERT INTO api_keys (key, name, email, rate_limit, expires_at, balance) VALUES (?, ?, ?, ?, ?, ?)'
    ).bind(key, name, email, rateLimit, expiresAt, balance).run();

    return json({ status: 'created', key, name, rate_limit: rateLimit, balance });
  }

  // POST /admin/keys/:id/topup — add balance
  if (path.match(/^\/admin\/keys\/\d+\/topup$/) && method === 'POST') {
    const id = path.split('/')[3];
    const body = await request.json();
    const amount = parseInt(body.amount) || 0;
    if (amount <= 0) return json({ error: 'amount must be positive' }, 400);

    await env.DB.prepare(
      'UPDATE api_keys SET balance = balance + ? WHERE id = ?'
    ).bind(amount, id).run();

    const row = await env.DB.prepare('SELECT key, balance FROM api_keys WHERE id = ?').bind(id).first();

    // Log transaction
    await env.DB.prepare(
      'INSERT INTO transactions (api_key, amount, type, note) VALUES (?, ?, ?, ?)'
    ).bind(row.key, amount, 'topup', body.note || `Top-up ${amount} VND`).run();

    return json({ status: 'topped_up', id, amount, new_balance: row.balance });
  }

  // POST /admin/keys/:id/toggle — activate/deactivate
  if (path.match(/^\/admin\/keys\/\d+\/toggle$/) && method === 'POST') {
    const id = path.split('/')[3];
    await env.DB.prepare(
      'UPDATE api_keys SET active = CASE WHEN active = 1 THEN 0 ELSE 1 END WHERE id = ?'
    ).bind(id).run();
    const row = await env.DB.prepare('SELECT id, active FROM api_keys WHERE id = ?').bind(id).first();
    return json({ status: 'toggled', id: row.id, active: row.active });
  }

  // POST /admin/keys/:id/edit — edit rate limit
  if (path.match(/^\/admin\/keys\/\d+\/edit$/) && method === 'POST') {
    const id = path.split('/')[3];
    const body = await request.json();
    const rateLimit = parseInt(body.rate_limit) || 10;
    await env.DB.prepare(
      'UPDATE api_keys SET rate_limit = ? WHERE id = ?'
    ).bind(rateLimit, id).run();
    return json({ status: 'updated', id, rate_limit: rateLimit });
  }

  // DELETE /admin/keys/:id — delete key
  if (path.match(/^\/admin\/keys\/\d+$/) && method === 'DELETE') {
    const id = path.split('/')[3];
    await env.DB.prepare('DELETE FROM api_keys WHERE id = ?').bind(id).run();
    return json({ status: 'deleted', id });
  }

  // GET /admin/usage — usage stats
  if (path === '/admin/usage' && method === 'GET') {
    const url = new URL(request.url);
    const days = parseInt(url.searchParams.get('days') || '7');
    const since = new Date(Date.now() - days * 86400000).toISOString();

    const { results } = await env.DB.prepare(`
      SELECT api_key, COUNT(*) as requests, 
             AVG(response_time_ms) as avg_time,
             SUM(CASE WHEN status = 200 THEN 1 ELSE 0 END) as success,
             SUM(CASE WHEN status != 200 THEN 1 ELSE 0 END) as errors,
             SUM(cost) as total_cost
      FROM usage_logs WHERE created_at > ? GROUP BY api_key
    `).bind(since).all();

    return json({ period_days: days, usage: results });
  }

  // GET /admin/stats — overall stats
  if (path === '/admin/stats' && method === 'GET') {
    const totalKeys = await env.DB.prepare('SELECT COUNT(*) as cnt FROM api_keys').first();
    const activeKeys = await env.DB.prepare('SELECT COUNT(*) as cnt FROM api_keys WHERE active = 1').first();
    const todayUsage = await env.DB.prepare(
      "SELECT COUNT(*) as cnt FROM usage_logs WHERE created_at > datetime('now', '-1 day')"
    ).first();
    const totalUsage = await env.DB.prepare('SELECT COUNT(*) as cnt FROM usage_logs').first();
    const revenue = await env.DB.prepare('SELECT COALESCE(SUM(total_spent), 0) as total FROM api_keys').first();
    const chars = await env.DB.prepare('SELECT COALESCE(SUM(chars), 0) as total FROM usage_logs WHERE status = 200').first();

    return json({
      total_keys: totalKeys.cnt,
      active_keys: activeKeys.cnt,
      requests_today: todayUsage.cnt,
      requests_total: totalUsage.cnt,
      total_revenue: revenue.total,
      total_chars: chars.total,
    });
  }

  // GET /admin/logs — detailed request logs
  if (path === '/admin/logs' && method === 'GET') {
    const url = new URL(request.url);
    const page = parseInt(url.searchParams.get('page')) || 1;
    const limit = Math.min(parseInt(url.searchParams.get('limit')) || 50, 100);
    const offset = (page - 1) * limit;

    const { results } = await env.DB.prepare(`
      SELECT id, api_key, key_name, voice_id, text_preview, text_length, 
             status, response_time_ms, cost, chars, ip, error_msg, created_at
      FROM usage_logs ORDER BY id DESC LIMIT ? OFFSET ?
    `).bind(limit, offset).all();

    const total = await env.DB.prepare('SELECT COUNT(*) as cnt FROM usage_logs').first();

    return json({
      logs: results || [],
      total: total.cnt,
      page,
      pages: Math.ceil(total.cnt / limit),
    });
  }

  // GET /admin/charts — chart data
  if (path === '/admin/charts' && method === 'GET') {
    const { results: daily } = await env.DB.prepare(`
      SELECT date(created_at) as date,
             COUNT(*) as requests,
             COALESCE(SUM(cost), 0) as revenue,
             COALESCE(SUM(chars), 0) as chars
      FROM usage_logs
      WHERE created_at > datetime('now', '-7 days')
      GROUP BY date(created_at)
      ORDER BY date ASC
    `).all();

    const totals_row = await env.DB.prepare(`
      SELECT COALESCE(SUM(CASE WHEN status = 200 THEN 1 ELSE 0 END), 0) as success,
             COALESCE(SUM(CASE WHEN status != 200 THEN 1 ELSE 0 END), 0) as errors
      FROM usage_logs
    `).first();

    const { results: top_users } = await env.DB.prepare(`
      SELECT a.name, a.key as api_key, a.total_spent
      FROM api_keys a
      WHERE a.total_spent > 0
      ORDER BY a.total_spent DESC
      LIMIT 10
    `).all();

    return json({
      daily: daily || [],
      totals: { success: totals_row.success, errors: totals_row.errors },
      top_users: top_users || [],
    });
  }

  return json({ error: 'Not found' }, 404);
}
